from flask import Flask, request, jsonify, render_template
from anthropic import Anthropic
import os
from dotenv import load_dotenv

load_dotenv()

app = Flask(__name__)
client = Anthropic(api_key=os.getenv("ANTHROPIC_API_KEY"))

BASE_PROMPT = """당신은 로아한의원 부천점의 친절한 상담 어시스턴트입니다.
직원이 환자(또는 잠재 고객)의 질문을 붙여넣으면, 직원이 환자에게 보낼 답변 초안을 작성해주세요.

아래는 병원 정보와 시술 내용, 응대 가이드입니다. 이 내용을 기반으로 답변하세요.

=== 지식베이스 시작 ===
{knowledge}
=== 지식베이스 끝 ===

[답변 작성 규칙]
1. 카카오톡·문자 형식에 맞게 자연스럽고 간결하게 작성
2. 지식베이스에 있는 정보만 사용하고, 없는 내용은 추측하지 말 것
3. 모르는 내용이나 개인 상담이 필요한 경우: 전화(032-324-1118) 또는 방문 상담 권유
4. 답변 초안만 작성하고 설명이나 주석은 달지 말 것
5. 가격 등 민감한 정보는 지식베이스에 명시된 경우에만 안내"""


def load_knowledge():
    try:
        with open("지식베이스.txt", "r", encoding="utf-8") as f:
            return f.read()
    except FileNotFoundError:
        return "(지식베이스 파일을 찾을 수 없습니다. 지식베이스.txt 파일을 확인해주세요.)"


@app.route("/")
def index():
    return render_template("index.html")


@app.route("/generate", methods=["POST"])
def generate():
    data = request.json
    question = data.get("question", "").strip()

    if not question:
        return jsonify({"error": "질문 내용이 없습니다."}), 400

    knowledge = load_knowledge()
    system_prompt = BASE_PROMPT.format(knowledge=knowledge)

    try:
        message = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            system=system_prompt,
            messages=[
                {
                    "role": "user",
                    "content": f"다음 환자 질문에 대한 답변 초안을 작성해주세요:\n\n{question}"
                }
            ]
        )
        answer = message.content[0].text
        return jsonify({"answer": answer})

    except Exception as e:
        return jsonify({"error": f"오류가 발생했습니다: {str(e)}"}), 500


if __name__ == "__main__":
    app.run(debug=False, port=5000)

